@using Tempo.Blazor.Components.DataTable
@using Tempo.Blazor.Interfaces
@using Tempo.Blazor.Models

<TmDataTable TItem="EmployeeDto"
             DataProvider="@_dataProvider"
             ViewContext="employees"
             ViewProvider="@_viewProvider"
             ViewFilterDefinitions="@_viewFilterDefs"
             ExternalFilterDefinitions="@_externalFilterDefs"
             ShowExternalFilterBuilder="true"
             DisplayResolver="ResolveDisplay"
             ViewCanCreateTenantViews="true"
             CurrentUserId="@_currentUserId"
             CurrentTenantId="@_currentTenantId"
             Selectable="true"
             ShowGrouping="true"
             DefaultPageSize="25"
             OnRowClick="HandleRowClick"
             OnSelectionChanged="HandleSelection">
    <SelectionActions>
        <TmButton OnClick="DeleteSelected" Variant="ButtonVariant.Danger">Delete</TmButton>
        <TmButton OnClick="ExportSelected">Export</TmButton>
    </SelectionActions>
    <TmDataTableColumn TItem="EmployeeDto" Title="Name" PropertyName="Name" Sortable="true" Filterable="true" Field="e => e.Name" />
    <TmDataTableColumn TItem="EmployeeDto" Title="Role" PropertyName="Role" Sortable="true" Filterable="true"
                       FilterType="FilterType.Select" FilterOptions="@_roleOptions" Field="e => e.Role" Groupable="true" />
    <TmDataTableColumn TItem="EmployeeDto" Title="Department" PropertyName="Department" Sortable="true" Filterable="true"
                       FilterType="FilterType.Select" FilterOptions="@_deptOptions" Field="e => e.Department" Groupable="true" />
    <TmDataTableColumn TItem="EmployeeDto" Title="Salary" PropertyName="Salary" Sortable="true"
                       Align="ColumnAlign.Right" Width="120px" Field="@(e => e.Salary.ToString("C"))" />
    <TmDataTableColumn TItem="EmployeeDto" Title="Active" PropertyName="IsActive" Sortable="true"
                       Align="ColumnAlign.Center" Field="@(e => e.IsActive ? "Yes" : "No")" />
</TmDataTable>

