        new() { FieldName = "Department", FieldLabel = "Department", FieldType = FilterFieldType.Select,
            Options = [new SelectOption<string>("Engineering", "Engineering"), new SelectOption<string>("Marketing", "Marketing"), new SelectOption<string>("Sales", "Sales")] },
        new() { FieldName = "IsActive", FieldLabel = "Active", FieldType = FilterFieldType.Boolean }
    ];

    private IReadOnlyList<SelectOption<string>> _roleOptions = [ new("Admin", "Admin"), new("User", "User"), new("Manager", "Manager") ];
