    /// </summary>
    private string? ResolveDisplay(string fieldName, string? rawValue)
    {
        if (rawValue is null)
        {
            return fieldName switch
            {
                "Name" => "Employee Name",
                "Role" => "Role",
                "Department" => "Department",
                "IsActive" => "Active",
                _ => null
            };
        }
        return (fieldName, rawValue) switch
        {
            ("Role", "Admin") => "Administrator",
            ("Role", "User") => "Regular User",
            ("Role", "Manager") => "Team Manager",
            _ => null
        };
    }

