using Tempo.Blazor.Interfaces;
using Tempo.Blazor.Models;
using System.Net.Http.Json;

/// <summary>
/// Basic server-side data provider — implements GetDataAsync for flat pagination.
/// GetGroupedDataAsync uses the default (returns null → client-side grouping fallback).
/// </summary>
public class EmployeeHttpDataProvider : IDataTableDataProvider<EmployeeDto>
{
    private readonly HttpClient _http;

    public EmployeeHttpDataProvider(HttpClient http) => _http = http;

    public async Task<PagedResult<EmployeeDto>> GetDataAsync(DataTableQuery query, CancellationToken ct = default)
    {
        var qs = $"?page={query.Page}&pageSize={query.PageSize}";
        if (!string.IsNullOrEmpty(query.SearchText))
            qs += $"&search={Uri.EscapeDataString(query.SearchText)}";
        if (!string.IsNullOrEmpty(query.SortColumn))
            qs += $"&sortBy={Uri.EscapeDataString(query.SortColumn)}&sortDesc={query.SortDescending}";
        foreach (var f in query.Filters)
            qs += $"&filterColumn={Uri.EscapeDataString(f.Column)}&filterOperator={Uri.EscapeDataString(f.Operator)}&filterValue={Uri.EscapeDataString(f.Value?.ToString() ?? "")}";

        return await _http.GetFromJsonAsync<PagedResult<EmployeeDto>>($"/api/employees{qs}", ct) ?? new();
    }
}

