using Tempo.Blazor.Interfaces;
using Tempo.Blazor.Models;
using System.Net.Http.Json;

/// <summary>
/// Full server-side data provider with server-side grouping and per-group pagination.
/// When grouping is active, the component calls GetGroupedDataAsync instead of GetDataAsync.
/// If GetGroupedDataAsync returns null, the component falls back to client-side grouping.
///
/// Per-group pagination: When the server returns GroupPaging metadata in the response,
/// TmDataTable automatically renders a mini-pager inside each expanded group (the global
/// footer pagination is hidden during grouping). When the user navigates within a group,
/// the component passes GroupPageRequests in the next DataTableQuery so the server can
/// return the correct page for each group independently.
/// </summary>
public class EmployeeGroupingDataProvider : IDataTableDataProvider<EmployeeDto>
{
    private readonly HttpClient _http;

    public EmployeeGroupingDataProvider(HttpClient http) => _http = http;

    public async Task<PagedResult<EmployeeDto>> GetDataAsync(DataTableQuery query, CancellationToken ct = default)
    {
        var url = BuildBaseUrl(query, $"/api/employees?page={query.Page}&pageSize={query.PageSize}");
        return await _http.GetFromJsonAsync<PagedResult<EmployeeDto>>(url, ct) ?? new();
    }

    /// <summary>
    /// Server-side grouping with per-group pagination.
    /// Returns GroupedPagedResult with Groups and optional GroupPaging metadata.
    /// The component renders a mini-pager per group when GroupPaging has TotalPages > 1.
    /// Return null to fall back to client-side grouping.
    /// </summary>
    public async Task<GroupedPagedResult<EmployeeDto>?> GetGroupedDataAsync(DataTableQuery query, CancellationToken ct = default)
    {
        if (query.GroupByColumns.Count == 0)
            return null;

        var url = BuildBaseUrl(query, $"/api/employees/grouped?groupPageSize={query.PageSize}");

        // Pass groupBy columns to server
        foreach (var col in query.GroupByColumns)
            url += $"&groupBy={Uri.EscapeDataString(col)}";

        // Pass per-group page requests (e.g. groupPage[Developer]=2&groupPage[Manager]=3)
        if (query.GroupPageRequests is { Count: > 0 })
        {
            foreach (var (key, page) in query.GroupPageRequests)
                url += $"&groupPage[{Uri.EscapeDataString(key)}]={page}";
        }

        return await _http.GetFromJsonAsync<GroupedPagedResult<EmployeeDto>>(url, ct);
    }

    private static string BuildBaseUrl(DataTableQuery query, string baseUrl)
    {
        var url = baseUrl +
            $"&sortColumn={Uri.EscapeDataString(query.SortColumn ?? "")}" +
            $"&sortDescending={query.SortDescending}" +
            $"&searchText={Uri.EscapeDataString(query.SearchText ?? "")}";

        foreach (var f in query.Filters)
            url += $"&filterColumn={Uri.EscapeDataString(f.Column)}" +
                   $"&filterOperator={Uri.EscapeDataString(f.Operator)}" +
                   $"&filterValue={Uri.EscapeDataString(f.Value?.ToString() ?? "")}";

        return url;
    }
}

// Server response models (already in Tempo.Blazor.Models):
// - GroupedPagedResult<T>: Groups, TotalCount, GroupByColumns, GroupPaging
// - DataGroup<T>: FieldName, Key, DisplayValue, Count, Items, SubGroups, Aggregations
// - GroupPagination: Page, PageSize, TotalCount, TotalPages, HasPreviousPage, HasNextPage
// - DataTableQuery.GroupPageRequests: IReadOnlyDictionary<string, int>? — per-group page navigation
//
// Per-group pagination flow:
// 1. Server returns GroupPaging dictionary (key = group value, e.g. "Developer")
// 2. TmDataTable renders TmPagination inside each group with TotalPages > 1
// 3. User clicks page 2 in "Developer" group
// 4. Component sets GroupPageRequests = { "Developer": 2 } and calls GetGroupedDataAsync
// 5. Server reads groupPage[Developer]=2 and returns page 2 for that group only
//
