using Tempo.Blazor.Interfaces;
using Tempo.Blazor.Models;
using System.Net.Http.Json;

public class ViewHttpProvider : IDataTableViewProvider
{
    private readonly HttpClient _http;

    public ViewHttpProvider(HttpClient http) => _http = http;

    public async Task<IEnumerable<DataTableView>> GetViewsAsync(string viewContext, string? tenantId = null, string? userId = null, CancellationToken ct = default)
    {
        var qs = $"?tenantId={tenantId}&userId={userId}";
        return await _http.GetFromJsonAsync<List<DataTableView>>($"/api/views/{viewContext}{qs}", ct) ?? [];
    }

    public async Task<DataTableView> SaveViewAsync(string viewContext, DataTableView view, string? tenantId = null, string? userId = null, CancellationToken ct = default)
    {
        var response = await _http.PostAsJsonAsync($"/api/views/{viewContext}?tenantId={tenantId}&userId={userId}", view, ct);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<DataTableView>(ct) ?? view;
    }

    public async Task DeleteViewAsync(string viewContext, string viewId, CancellationToken ct = default)
    {
        await _http.DeleteAsync($"/api/views/{viewContext}/{viewId}", ct);
    }

    public async Task<DataTableView?> GetDefaultViewAsync(string viewContext, string? tenantId = null, string? userId = null, CancellationToken ct = default)
    {
        return await _http.GetFromJsonAsync<DataTableView?>($"/api/views/{viewContext}/default?tenantId={tenantId}&userId={userId}", ct);
    }

    public async Task SetDefaultViewAsync(string viewContext, string viewId, string? tenantId = null, string? userId = null, CancellationToken ct = default)
    {
        await _http.PutAsync($"/api/views/{viewContext}/{viewId}/set-default?tenantId={tenantId}&userId={userId}", null, ct);
    }
}

